  ('social-worker-moex-02553', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關性別預算的敘述，下列何者最正確？', '["臺灣已將性別觀點分析全面地導入政府的預算之中", "性別預算是立基於經濟效率、資訊權利、國際承諾和性別主流化", "性別預算原稱婦女預算，規定預算編列者有一定比例的婦女名額", "性別預算是把「性別」列為預算的項目，並編列一定比例的支出金額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
