  ('social-worker-moex-02560', 'social-worker', 'social-worker-moex-104-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '根據國際災害研究的發現及災害服務組織的經驗總結，災難管理週期可分為災難預防期、災難整備期、 災難應變期與災難重建期。下列那一項是災難應變期最重要的工作？', '["實施防災教育", "組成災難應變小組", "組訓救災人員", "動員救災資源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "7528bca53179", "answer_pdf_sha1": "6a2111ca5bab", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
